package main

import (
	"entire-dashboard/db"
	gitreader "entire-dashboard/git"
	"entire-dashboard/handlers"
	"flag"
	"log"
	"net/http"
	"os"
	"path/filepath"
)

func main() {
	repoPath := flag.String("repo", "", "Path to git repository with Entire enabled")
	port := flag.String("port", "8080", "Server port")
	flag.Parse()

	if *repoPath == "" {
		log.Fatal("--repo flag is required")
	}

	// Resolve absolute path
	absRepo, err := filepath.Abs(*repoPath)
	if err != nil {
		log.Fatalf("resolve repo path: %v", err)
	}

	// DB stored alongside the binary in a data directory
	dataDir := filepath.Join(absRepo, ".entire", "dashboard")
	if err := os.MkdirAll(dataDir, 0755); err != nil {
		log.Fatalf("create data dir: %v", err)
	}
	dbPath := filepath.Join(dataDir, "dashboard.db")

	store, err := db.New(dbPath)
	if err != nil {
		log.Fatalf("open db: %v", err)
	}
	defer store.Close()

	reader := gitreader.NewReader(absRepo)
	h := handlers.New(store, reader)

	mux := http.NewServeMux()

	// API routes
	mux.HandleFunc("GET /api/daily-stats", h.GetDailyStats)
	mux.HandleFunc("GET /api/sessions", h.GetSessions)
	mux.HandleFunc("POST /api/sync", h.Sync)

	// Serve frontend static files
	frontendDir := filepath.Join(filepath.Dir(os.Args[0]), "..", "frontend", "dist")
	if _, err := os.Stat(frontendDir); err == nil {
		mux.Handle("/", http.FileServer(http.Dir(frontendDir)))
	} else {
		// Fallback: serve from relative path during development
		devFrontend := filepath.Join(".", "..", "frontend", "dist")
		if _, err := os.Stat(devFrontend); err == nil {
			mux.Handle("/", http.FileServer(http.Dir(devFrontend)))
		}
	}

	// CORS middleware for development
	handler := corsMiddleware(mux)

	log.Printf("Starting server on :%s (repo: %s)", *port, absRepo)
	log.Fatal(http.ListenAndServe(":"+*port, handler))
}

func corsMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Access-Control-Allow-Origin", "*")
		w.Header().Set("Access-Control-Allow-Methods", "GET, POST, OPTIONS")
		w.Header().Set("Access-Control-Allow-Headers", "Content-Type")
		if r.Method == "OPTIONS" {
			w.WriteHeader(http.StatusOK)
			return
		}
		next.ServeHTTP(w, r)
	})
}

