package handlers

import (
	"encoding/json"
	"entire-dashboard/db"
	gitreader "entire-dashboard/git"
	"log"
	"net/http"
)

type Handler struct {
	store  *db.Store
	reader *gitreader.Reader
}

func New(store *db.Store, reader *gitreader.Reader) *Handler {
	return &Handler{store: store, reader: reader}
}

func (h *Handler) GetDailyStats(w http.ResponseWriter, r *http.Request) {
	stats, err := h.store.GetDailyStats()
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	writeJSON(w, stats)
}

func (h *Handler) GetSessions(w http.ResponseWriter, r *http.Request) {
	sessions, err := h.store.GetSessions()
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	writeJSON(w, sessions)
}

// Sync reads from the git shadow branch and upserts into SQLite.
func (h *Handler) Sync(w http.ResponseWriter, r *http.Request) {
	sessions, err := h.reader.ReadAllSessions()
	if err != nil {
		http.Error(w, "failed to read sessions: "+err.Error(), http.StatusInternalServerError)
		return
	}

	inserted := 0
	for _, sess := range sessions {
		exists, err := h.store.SessionExists(sess.SessionID)
		if err != nil {
			log.Printf("check exists error: %v", err)
			continue
		}
		if exists {
			continue
		}
		if err := h.store.UpsertSession(sess); err != nil {
			log.Printf("upsert error: %v", err)
			continue
		}
		inserted++
	}

	writeJSON(w, map[string]any{
		"total_found": len(sessions),
		"inserted":    inserted,
		"message":     "sync complete",
	})
}

func writeJSON(w http.ResponseWriter, v any) {
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(v)
}

