package git

import (
	"encoding/json"
	"entire-dashboard/models"
	"fmt"
	"os/exec"
	"strconv"
	"strings"
)

const shadowBranch = "entire/checkpoints/v1"

// Reader reads Entire checkpoint data from a git repository's shadow branch.
type Reader struct {
	repoPath string
}

func NewReader(repoPath string) *Reader {
	return &Reader{repoPath: repoPath}
}

// ReadAllSessions extracts all session metadata from the shadow branch.
func (r *Reader) ReadAllSessions() ([]models.Session, error) {
	// List top-level directories (2-char prefixes)
	prefixes, err := r.lsTree(shadowBranch)
	if err != nil {
		return nil, fmt.Errorf("list prefixes: %w", err)
	}

	var sessions []models.Session
	for _, prefix := range prefixes {
		// List checkpoint IDs under each prefix
		checkpointIDs, err := r.lsTree(shadowBranch + ":" + prefix + "/")
		if err != nil {
			continue
		}
		for _, cpID := range checkpointIDs {
			path := prefix + "/" + cpID
			ss, err := r.readCheckpointSessions(path, prefix+cpID)
			if err != nil {
				continue
			}
			sessions = append(sessions, ss...)
		}
	}
	return sessions, nil
}

func (r *Reader) readCheckpointSessions(treePath, checkpointID string) ([]models.Session, error) {
	// List entries in this checkpoint (numbered session dirs + metadata.json)
	entries, err := r.lsTree(shadowBranch + ":" + treePath + "/")
	if err != nil {
		return nil, err
	}

	var sessions []models.Session
	for _, entry := range entries {
		// Only process numbered directories (session indices)
		if _, err := strconv.Atoi(entry); err != nil {
			continue
		}

		metaPath := treePath + "/" + entry + "/metadata.json"
		meta, err := r.readSessionMeta(metaPath)
		if err != nil {
			continue
		}

		prompt := r.readFileContent(treePath + "/" + entry + "/prompt.txt")

		sessions = append(sessions, models.Session{
			CheckpointID:    meta.CheckpointID,
			SessionID:       meta.SessionID,
			Agent:           meta.Agent,
			Branch:          meta.Branch,
			CreatedAt:       meta.CreatedAt,
			Prompt:          truncate(prompt, 500),
			AgentLines:      meta.Attribution.AgentLines,
			HumanAdded:      meta.Attribution.HumanAdded,
			HumanModified:   meta.Attribution.HumanModified,
			HumanRemoved:    meta.Attribution.HumanRemoved,
			TotalCommitted:  meta.Attribution.TotalCommitted,
			AgentPercentage: meta.Attribution.AgentPercentage,
			InputTokens:     meta.TokenUsage.InputTokens,
			OutputTokens:    meta.TokenUsage.OutputTokens,
			APICallCount:    meta.TokenUsage.APICallCount,
		})
	}
	return sessions, nil
}

func (r *Reader) readSessionMeta(path string) (models.SessionMeta, error) {
	var meta models.SessionMeta
	content := r.readFileContent(path)
	if content == "" {
		return meta, fmt.Errorf("empty content at %s", path)
	}
	err := json.Unmarshal([]byte(content), &meta)
	return meta, err
}

func (r *Reader) readFileContent(path string) string {
	out, err := r.gitShow(shadowBranch + ":" + path)
	if err != nil {
		return ""
	}
	return out
}

func (r *Reader) lsTree(ref string) ([]string, error) {
	out, err := exec.Command("git", "-C", r.repoPath, "ls-tree", "--name-only", ref).Output()
	if err != nil {
		return nil, err
	}
	lines := strings.Split(strings.TrimSpace(string(out)), "\n")
	var result []string
	for _, l := range lines {
		l = strings.TrimSpace(l)
		if l != "" {
			result = append(result, l)
		}
	}
	return result, nil
}

func (r *Reader) gitShow(ref string) (string, error) {
	out, err := exec.Command("git", "-C", r.repoPath, "show", ref).Output()
	if err != nil {
		return "", err
	}
	return string(out), nil
}

func truncate(s string, maxLen int) string {
	if len(s) <= maxLen {
		return s
	}
	return s[:maxLen] + "..."
}

package db

import (
	"database/sql"
	"entire-dashboard/models"
	"fmt"

	_ "github.com/mattn/go-sqlite3"
)

type Store struct {
	db *sql.DB
}

func New(path string) (*Store, error) {
	db, err := sql.Open("sqlite3", path+"?_journal_mode=WAL")
	if err != nil {
		return nil, fmt.Errorf("open db: %w", err)
	}
	if err := migrate(db); err != nil {
		return nil, fmt.Errorf("migrate: %w", err)
	}
	return &Store{db: db}, nil
}

func migrate(db *sql.DB) error {
	_, err := db.Exec(`
		CREATE TABLE IF NOT EXISTS sessions (
			id INTEGER PRIMARY KEY AUTOINCREMENT,
			checkpoint_id TEXT NOT NULL,
			session_id TEXT NOT NULL UNIQUE,
			agent TEXT NOT NULL DEFAULT '',
			branch TEXT NOT NULL DEFAULT '',
			created_at TEXT NOT NULL DEFAULT '',
			prompt TEXT NOT NULL DEFAULT '',
			agent_lines INTEGER NOT NULL DEFAULT 0,
			human_added INTEGER NOT NULL DEFAULT 0,
			human_modified INTEGER NOT NULL DEFAULT 0,
			human_removed INTEGER NOT NULL DEFAULT 0,
			total_committed INTEGER NOT NULL DEFAULT 0,
			agent_percentage REAL NOT NULL DEFAULT 0,
			input_tokens INTEGER NOT NULL DEFAULT 0,
			output_tokens INTEGER NOT NULL DEFAULT 0,
			api_call_count INTEGER NOT NULL DEFAULT 0
		);
		CREATE INDEX IF NOT EXISTS idx_sessions_created_at ON sessions(created_at);
	`)
	return err
}

func (s *Store) UpsertSession(sess models.Session) error {
	_, err := s.db.Exec(`
		INSERT INTO sessions (
			checkpoint_id, session_id, agent, branch, created_at, prompt,
			agent_lines, human_added, human_modified, human_removed,
			total_committed, agent_percentage,
			input_tokens, output_tokens, api_call_count
		) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
		ON CONFLICT(session_id) DO UPDATE SET
			agent=excluded.agent, branch=excluded.branch,
			created_at=excluded.created_at, prompt=excluded.prompt,
			agent_lines=excluded.agent_lines, human_added=excluded.human_added,
			human_modified=excluded.human_modified, human_removed=excluded.human_removed,
			total_committed=excluded.total_committed, agent_percentage=excluded.agent_percentage,
			input_tokens=excluded.input_tokens, output_tokens=excluded.output_tokens,
			api_call_count=excluded.api_call_count
	`,
		sess.CheckpointID, sess.SessionID, sess.Agent, sess.Branch, sess.CreatedAt, sess.Prompt,
		sess.AgentLines, sess.HumanAdded, sess.HumanModified, sess.HumanRemoved,
		sess.TotalCommitted, sess.AgentPercentage,
		sess.InputTokens, sess.OutputTokens, sess.APICallCount,
	)
	return err
}

func (s *Store) GetDailyStats() ([]models.DailyStat, error) {
	rows, err := s.db.Query(`
		SELECT
			substr(created_at, 1, 10) AS date,
			SUM(agent_lines) AS agent_lines,
			SUM(human_added) AS human_lines,
			SUM(agent_lines) + SUM(human_added) AS total_lines,
			CASE WHEN SUM(agent_lines) + SUM(human_added) > 0
				THEN ROUND(CAST(SUM(agent_lines) AS REAL) / (SUM(agent_lines) + SUM(human_added)) * 100, 1)
				ELSE 0
			END AS agent_percentage,
			COUNT(*) AS session_count
		FROM sessions
		GROUP BY substr(created_at, 1, 10)
		ORDER BY date
	`)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var stats []models.DailyStat
	for rows.Next() {
		var s models.DailyStat
		if err := rows.Scan(&s.Date, &s.AgentLines, &s.HumanLines, &s.TotalLines, &s.AgentPercentage, &s.SessionCount); err != nil {
			return nil, err
		}
		stats = append(stats, s)
	}
	return stats, rows.Err()
}

func (s *Store) GetSessions() ([]models.Session, error) {
	rows, err := s.db.Query(`
		SELECT id, checkpoint_id, session_id, agent, branch, created_at, prompt,
			agent_lines, human_added, human_modified, human_removed,
			total_committed, agent_percentage,
			input_tokens, output_tokens, api_call_count
		FROM sessions
		ORDER BY created_at DESC
	`)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var sessions []models.Session
	for rows.Next() {
		var s models.Session
		if err := rows.Scan(
			&s.ID, &s.CheckpointID, &s.SessionID, &s.Agent, &s.Branch, &s.CreatedAt, &s.Prompt,
			&s.AgentLines, &s.HumanAdded, &s.HumanModified, &s.HumanRemoved,
			&s.TotalCommitted, &s.AgentPercentage,
			&s.InputTokens, &s.OutputTokens, &s.APICallCount,
		); err != nil {
			return nil, err
		}
		sessions = append(sessions, s)
	}
	return sessions, rows.Err()
}

func (s *Store) SessionExists(sessionID string) (bool, error) {
	var count int
	err := s.db.QueryRow("SELECT COUNT(*) FROM sessions WHERE session_id = ?", sessionID).Scan(&count)
	return count > 0, err
}

func (s *Store) Close() error {
	return s.db.Close()
}

