10→  const [sessions, setSessions] = useState<Session[]>([]);
11→  const [syncing, setSyncing] = useState(false);
12→  const [lastSynced, setLastSynced] = useState<string>("");
13→
14→  const loadData = useCallback(async () => {
15→    const [stats, sess] = await Promise.all([fetchDailyStats(), fetchSessions()]);
16→    setDailyStats(stats);
17→    setSessions(sess);
18→  }, []);
