import { useEffect, useState, useCallback } from "react";
import { DailyDashboard } from "./components/DailyDashboard";
import { SessionTimeline } from "./components/SessionTimeline";
import { fetchDailyStats, fetchSessions, syncData } from "./api";
import type { DailyStat, Session } from "./types";
import "./App.css";

function App() {
  const [dailyStats, setDailyStats] = useState<DailyStat[]>([]);
  const [sessions, setSessions] = useState<Session[]>([]);
  const [syncing, setSyncing] = useState(false);
  const [lastSynced, setLastSynced] = useState<string>("");

  const loadData = useCallback(async () => {
    const [stats, sess] = await Promise.all([fetchDailyStats(), fetchSessions()]);
    setDailyStats(stats);
    setSessions(sess);
  }, []);

  useEffect(() => {
    loadData();
  }, [loadData]);

  const handleSync = async () => {
    setSyncing(true);
    try {
      await syncData();
      setLastSynced(new Date().toLocaleString("ja-JP"));
      await loadData();
    } catch {
      setLastSynced("Sync failed");
    } finally {
      setSyncing(false);
    }
  };

  // Compute KPIs
  const totalAgent = dailyStats.reduce((sum, d) => sum + d.agent_lines, 0);
  const totalHuman = dailyStats.reduce((sum, d) => sum + d.human_lines, 0);
  const totalAll = totalAgent + totalHuman;
  const overallPct = totalAll > 0 ? ((totalAgent / totalAll) * 100).toFixed(1) : "0.0";
  const totalSessions = sessions.length;

  return (
    <div className="dashboard">
      <header className="header">
        <h1 className="header-title">Entire Dashboard</h1>
        <div className="header-actions">
          {lastSynced && <span className="sync-status">Last synced: {lastSynced}</span>}
          <button onClick={handleSync} disabled={syncing} className="sync-button">
            {syncing ? "Syncing..." : "Sync"}
          </button>
        </div>
      </header>

      {/* KPI: Overview indicators - most important metric (AI Ratio) at top-left */}
      <div className="kpi-row">
        <div className="kpi-card kpi-card--primary">
          <div className="kpi-label">AI Contribution Ratio</div>
          <div className="kpi-value">
            {overallPct}<span className="kpi-unit">%</span>
          </div>
        </div>
        <div className="kpi-card">
          <div className="kpi-label">AI Lines</div>
          <div className="kpi-value">{totalAgent.toLocaleString()}</div>
        </div>
        <div className="kpi-card">
          <div className="kpi-label">Human Lines</div>
          <div className="kpi-value">{totalHuman.toLocaleString()}</div>
        </div>
        <div className="kpi-card">
          <div className="kpi-label">Sessions</div>
          <div className="kpi-value">{totalSessions}</div>
        </div>
      </div>

      {/* Daily Chart: Trend over time */}
      <DailyDashboard data={dailyStats} />

      {/* Session Detail: Individual session breakdown */}
      <SessionTimeline sessions={sessions} />
    </div>
  );
}

export default App;

